import{_ as a,o as t,c as r,S as o}from"./chunks/framework.C6RQlTYc.js";const f=JSON.parse('{"title":"Transformer 架构","description":"","frontmatter":{},"headers":[],"relativePath":"直击概念/17ai/s_ai_7-transformer.md","filePath":"直击概念/17ai/s_ai_7-transformer.md","lastUpdated":1778207238000}'),n={name:"直击概念/17ai/s_ai_7-transformer.md"};function i(l,e,s,d,h,c){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="transformer-架构" tabindex="-1">Transformer 架构 <a class="header-anchor" href="#transformer-架构" aria-label="Permalink to &quot;Transformer 架构&quot;">​</a></h1><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><p>Transformer 是 2017 年由 Google 在论文《Attention Is All You Need》中提出的神经网络架构，<strong>完全基于注意力机制</strong>，彻底摆脱了 RNN/LSTM 的循环结构。它是当前所有大语言模型（GPT、LLaMA、Claude 等）的基础骨架。</p><p>Transformer 的核心创新在于实现了<strong>并行计算</strong>和<strong>长距离依赖建模</strong>，解决了 RNN 在处理长序列时的效率瓶颈。</p><h2 id="核心结构" tabindex="-1">核心结构 <a class="header-anchor" href="#核心结构" aria-label="Permalink to &quot;核心结构&quot;">​</a></h2><p>Transformer 采用 Encoder-Decoder 结构：</p><h3 id="encoder-编码器" tabindex="-1">Encoder（编码器） <a class="header-anchor" href="#encoder-编码器" aria-label="Permalink to &quot;Encoder（编码器）&quot;">​</a></h3><p>将输入序列转换为上下文表示，由多个相同的层堆叠而成，每层包含：</p><ol><li><strong>Multi-Head Self-Attention</strong>：让每个 token 关注序列中的所有 token</li><li><strong>Add &amp; Norm</strong>：残差连接 + 层归一化</li><li><strong>Feed Forward Network（FFN）</strong>：两层全连接网络 + 激活函数</li><li><strong>Add &amp; Norm</strong>：残差连接 + 层归一化</li></ol><h3 id="decoder-解码器" tabindex="-1">Decoder（解码器） <a class="header-anchor" href="#decoder-解码器" aria-label="Permalink to &quot;Decoder（解码器）&quot;">​</a></h3><p>基于 Encoder 输出和已生成的 token 预测下一个 token：</p><ol><li><strong>Masked Multi-Head Self-Attention</strong>：自注意力（遮挡未来位置）</li><li><strong>Multi-Head Cross-Attention</strong>：关注 Encoder 的输出</li><li><strong>FFN + 残差连接和归一化</strong></li></ol><p>现代 LLM（如 GPT 系列）通常只使用 Decoder 部分（Decoder-Only），Encoder-Only 架构如 BERT 用于理解任务，Encoder-Decoder 架构如 T5 用于生成任务。</p><h2 id="关键组件" tabindex="-1">关键组件 <a class="header-anchor" href="#关键组件" aria-label="Permalink to &quot;关键组件&quot;">​</a></h2><h3 id="self-attention-自注意力" tabindex="-1">Self-Attention（自注意力） <a class="header-anchor" href="#self-attention-自注意力" aria-label="Permalink to &quot;Self-Attention（自注意力）&quot;">​</a></h3><p>每个 token 与序列中所有 token 计算关联度：</p><ul><li>Q（Query）：当前 token 想&quot;查询&quot;什么</li><li>K（Key）：每个 token 的&quot;索引&quot;标签</li><li>V（Value）：每个 token 的实际内容</li></ul><p><strong>Scaled Dot-Product Attention</strong> 公式：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>Attention(Q, K, V) = softmax(QK^T / √d_k) · V</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="multi-head-attention-多头注意力" tabindex="-1">Multi-Head Attention（多头注意力） <a class="header-anchor" href="#multi-head-attention-多头注意力" aria-label="Permalink to &quot;Multi-Head Attention（多头注意力）&quot;">​</a></h3><p>将 Q、K、V 投影到多个子空间，在每个子空间独立计算注意力，然后拼接。<strong>每个&quot;头&quot;可以学习不同类型的注意力模式</strong>（如语法关系、语义关联等）。</p><h3 id="positional-encoding-位置编码" tabindex="-1">Positional Encoding（位置编码） <a class="header-anchor" href="#positional-encoding-位置编码" aria-label="Permalink to &quot;Positional Encoding（位置编码）&quot;">​</a></h3><p>Transformer 本身不具备序列顺序感知，需要注入位置信息：</p><ul><li><strong>绝对位置编码</strong>：sin/cos 函数或可学习的位置向量</li><li><strong>相对位置编码</strong>：编码 token 间的相对距离（RoPE 是现代 LLM 的主流选择）</li></ul><h3 id="feed-forward-network-ffn" tabindex="-1">Feed Forward Network（FFN） <a class="header-anchor" href="#feed-forward-network-ffn" aria-label="Permalink to &quot;Feed Forward Network（FFN）&quot;">​</a></h3><p>两层全连接网络，中间使用激活函数（GELU/SwiGLU），为模型引入非线性。FFN 占模型参数的约 2/3。</p><h2 id="面试常问" tabindex="-1">面试常问 <a class="header-anchor" href="#面试常问" aria-label="Permalink to &quot;面试常问&quot;">​</a></h2><ul><li>Transformer 相比 RNN 的优势有哪些？</li><li>Self-Attention 的 Q、K、V 分别是什么含义？</li><li>为什么需要位置编码？有哪些实现方式？</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/1706.03762" target="_blank" rel="noreferrer">Attention Is All You Need</a></li><li><a href="https://jalammar.github.io/illustrated-transformer/" target="_blank" rel="noreferrer">The Illustrated Transformer</a></li></ul>',30)])])}const p=a(n,[["render",i]]);export{f as __pageData,p as default};
